// ═══════════════════════════════════════════════════════════════
// NORMALIZE & DEDUP — Config-based adapter for any job board
// To add a new board: add an entry to BOARD_CONFIG, wire the
// Apify node to this Code node, done. Nothing else changes.
// ═══════════════════════════════════════════════════════════════

const BOARD_CONFIG = {
  '2a. Scrape LinkedIn': {
    source: 'LinkedIn',
    fields: {
      id:          'id',
      title:       ['title', 'jobTitle'],
      company:     ['companyName', 'company'],
      location:    'location',
      description: ['descriptionText', 'description'],
      url:         ['link', 'url'],
      applyUrl:    ['applyUrl', 'link'],
      postedAt:    'postedAt',
      salary:      'salary',
      remote:      'workRemoteAllowed',
      seniority:   ['seniorityLevel', 'seniority'],
      country:     'country',
    }
  },
  '2b. Scrape Indeed': {
    source: 'Indeed',
    fields: {
      id:          'key',
      title:       'title',
      company:     'employer.name',
      location:    ['location.formattedLocation', 'location.city'],
      description: 'description.text',
      url:         ['url', 'jobUrl'],
      applyUrl:    ['url', 'jobUrl'],
      postedAt:    'datePublished',
      salary:      null,
      remote:      null,
      seniority:   null,
      country:     'location.countryCode',
    }
  },
  '2c. Scrape StepStone': {
    source: 'StepStone',
    fields: {
      id:          'id',
      title:       'title',
      company:     'company_details.company_name',
      location:    'workplace_details.job_location',
      description: 'content_details.full_description',
      url:         'source.url',
      applyUrl:    'detail_page.applying_details.applying_url',
      postedAt:    'posting_details.published_at',
      salary:      'compensation_details.detail_salary',
      remote:      'workplace_details.work_arrangement',
      seniority:   null,
      country:     null,  // StepStone.de is DACH-only — skip code filter
    }
  },
  '2d. Scrape Glassdoor': {
    source: 'Glassdoor',
    fields: {
      id:          'key',
      title:       'title',
      company:     ['company.companyName', 'company.name', 'companyName', 'employer_name', 'employer'],
      location:    ['location_city', 'location', 'location_country'],
      description: 'description_text',
      url:         'jobUrl',
      applyUrl:    'applyUrl',
      postedAt:    'datePublished',
      salary:      null,  // flat baseSalary_min/max handled in extractSalary
      remote:      'remoteWorkTypes',
      seniority:   null,
      country:     null,  // location_country is "Germany" not a code; Glassdoor.de is DACH-only
    }
  },
  '2e. Scrape Xing': {
    source: 'Xing',
    fields: {
      id:          'job_id',
      title:       'title',
      company:     'company',
      location:    'location',
      description: 'description_text',
      url:         'url',
      applyUrl:    'apply_url',
      postedAt:    'date_posted',
      salary:      'salary',
      remote:      'remote',
      seniority:   null,
      country:     'location_country_code',
    }
  },
};

const ALLOWED_COUNTRIES = new Set(['DE', 'AT', 'CH', 'NL', 'BE', '']);

function getNestedValue(obj, path) {
  if (!path) return undefined;
  return path.split('.').reduce((o, k) => (o && o[k] !== undefined) ? o[k] : undefined, obj);
}

function resolveField(obj, mapping) {
  if (mapping === null || mapping === undefined) return '';
  if (Array.isArray(mapping)) {
    for (const path of mapping) {
      const val = getNestedValue(obj, path);
      if (val !== undefined && val !== null && val !== '') return val;
    }
    return '';
  }
  return getNestedValue(obj, mapping) || '';
}

function extractSalary(obj, config) {
  const raw = resolveField(obj, config.fields.salary);
  // Already a string (Xing, LinkedIn)
  if (raw && typeof raw === 'string' && raw.length > 0) return raw;
  // StepStone: { min, max, currency, period }
  if (raw && typeof raw === 'object' && raw.min) {
    const { min, max, currency, currencyIso, period } = raw;
    return `${currency || currencyIso || ''} ${min}${max ? `-${max}` : ''}/${period || ''}`.trim();
  }
  // LinkedIn: baseSalary nested object
  if (obj.baseSalary && obj.baseSalary.min) {
    const { min, max, currencyCode, unitOfWork } = obj.baseSalary;
    return `${currencyCode || ''} ${min}-${max}/${unitOfWork || ''}`.trim();
  }
  // Glassdoor: flat baseSalary_min / baseSalary_max fields
  if (obj.baseSalary_min) {
    const { baseSalary_min: min, baseSalary_max: max, salary_currency: cur, salary_period: period } = obj;
    return `${cur || ''} ${min}${max ? `-${max}` : ''}/${period || ''}`.trim();
  }
  return '';
}

function extractCompanyFromUrl(url) {
  if (!url) return '';
  // Glassdoor pattern: /job-listing/...-at-COMPANY-NAME-JV_...
  const glassdoorMatch = String(url).match(/-at-([\w-]+?)-JV_/i);
  if (glassdoorMatch) {
    return glassdoorMatch[1].replace(/-/g, ' ').trim();
  }
  return '';
}

const jobs = [];

for (const [nodeName, config] of Object.entries(BOARD_CONFIG)) {
  let items;
  try {
    items = $(nodeName).all();
  } catch (e) {
    continue;
  }
  if (!items || items.length === 0) continue;

  for (const item of items) {
    const d = item.json;
    if (!d || typeof d !== 'object') continue;

    const desc = String(resolveField(d, config.fields.description));
    if (desc.length < 20) continue;

    const country = String(resolveField(d, config.fields.country) || '').toUpperCase();
    if (country && !ALLOWED_COUNTRIES.has(country)) continue;

    const rawCompany = String(resolveField(d, config.fields.company));
    jobs.push({
      source:      config.source,
      id:          String(resolveField(d, config.fields.id)),
      title:       String(resolveField(d, config.fields.title)),
      company:     rawCompany || extractCompanyFromUrl(resolveField(d, config.fields.url)) || 'Unknown Company',
      location:    String(resolveField(d, config.fields.location)),
      description: desc,
      url:         String(resolveField(d, config.fields.url)),
      applyUrl:    String(resolveField(d, config.fields.applyUrl)),
      postedAt:    String(resolveField(d, config.fields.postedAt)),
      salary:      extractSalary(d, config),
      remote:      !!resolveField(d, config.fields.remote),
      seniority:   String(resolveField(d, config.fields.seniority)),
    });
  }
}

const seen = new Set();
const unique = [];
for (const job of jobs) {
  const key = job.url || job.applyUrl || `${job.company}::${job.title}`;
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push(job);
}

if (unique.length === 0) {
  return [{ json: { error: 'No valid jobs after normalize + dedup. Check Apify outputs and country filter.', rawCount: jobs.length } }];
}

return unique.map(j => ({ json: j }));

const rows = $input.all();
if (rows.length === 0) {
  return [{ json: { _emptySheet: true } }];
}
return rows;

// Get all scraped jobs from normalize step
const jobs = $('4. Normalize & Merge Jobs').all();

// Pass through error sentinel from node 4 — don't mask it as 'skipped'
if (jobs.length === 1 && jobs[0].json.error) {
  return [{ json: { error: jobs[0].json.error, message: jobs[0].json.error, totalScraped: 0 } }];
}

// Build set of already-seen job URLs from Sheets
const seenUrls = new Set();
const seenSheetCompanyRole = new Set();
try {
  const sheetRows = $('2f. Read Applied Jobs').all();
  for (const row of sheetRows) {
    // Only suppress URLs for jobs that were actually processed (not skipped)
    // Skipped rows (Applied = 'N/A') should remain eligible for re-evaluation
    if ((row.json['Applied'] || '').trim() === 'N/A') continue;
    const url = (row.json['Raw URL'] || row.json['Job URL'] || '').trim();
    if (url) seenUrls.add(url);
    const co = (row.json['Company'] || '').toLowerCase().trim();
    const ro = (row.json['Role'] || '').toLowerCase().trim();
    if (co && ro) seenSheetCompanyRole.add(`${co}::${ro}`);
  }
} catch (e) {
  // Sheet is empty on first run — that's fine
}

// Filter to only new jobs not yet in Sheets (by URL or company+role)
const urlFiltered = jobs.filter(job => {
  const url = (job.json.url || job.json.applyUrl || '').trim();
  if (!url) return false;
  if (seenUrls.has(url)) return false;
  const crKey = `${(job.json.company || '').toLowerCase().trim()}::${(job.json.title || '').toLowerCase().trim()}`;
  if (seenSheetCompanyRole.has(crKey)) return false;
  return true;
});

if (urlFiltered.length === 0) {
  return [{ json: { skipped: true, message: 'No new jobs — all already logged in Sheets', totalScraped: jobs.length } }];
}

console.log(`New jobs to process: ${urlFiltered.length} / ${jobs.length} scraped`);
return urlFiltered;

const resumeItem = $('7. GET Resume Context').first();
// If the resume server is down, continueOnFail gives us an error item.
// Fall back to an empty resume object so the pipeline can still run and log jobs.
const resumeContext = (resumeItem.json && !resumeItem.json.error)
  ? resumeItem.json
  : {};

const jobs = $('6. Filter Duplicates').all();

// Short-circuit: no new jobs today — pass sentinel through without attaching resume.
// This prevents a wasted Gemini API call and a misleading Sheet row.
if (jobs.length === 1 && (jobs[0].json.skipped || jobs[0].json.error)) {
  return [{ json: jobs[0].json }];
}

const resumeFallback = Object.keys(resumeContext).length === 0;

if (resumeFallback) {
  return [{ json: { error: true, message: 'Resume server unavailable — skipping all jobs to avoid blind processing', skipped: true } }];
}

return jobs.map(job => ({
  json: {
    ...job.json,
    resume: resumeContext,
    _resumeFallback: false
  }
}));

const item = $json;

// Skip non-job sentinels (scraper errors, no-new-jobs) — pass through as-is
if (item.skipped || item.error) {
  return {
    json: {
      ...item,
      _skip: true,
      _pipelineSentinel: true,
    },
  };
}

// ===== Role-Type Pre-Filter =====
// Reject fundamentally misaligned roles BEFORE burning a Gemini API call.
const ROLE_REJECT_PATTERNS = [
  /\b(au(?:ß|ss)endienst|verkauf|sales\s*rep)\b/i,
  /\b(kundenberater|kundenbetreuer|kundenservice|customer\s*service)\b/i,
  /\b(disponent|logistik|versand|spedition|lagerlogistik|supply\s*chain)\b/i,
  /\b(personal(?:referent|leiter|manager|wesen)|recruiting|recruiter|human\s*resource|hr\s*manager|talent\s*acquisition)\b/i,
  /\b(marketing\s*manager|communications|public\s*relations|pr\s*manager)\b/i,
  /\b(buchhalter|accounting|finanzbuchhalter|steuerberater)\b/i,
  /\b(linienf(?:ü|ue)hrer|produktionsleiter|schichtf(?:ü|ue)hrer|maschinenf(?:ü|ue)hrer|anlagenf(?:ü|ue)hrer)\b/i,
  /\b(inbetriebnahme(?:leiter|ingenieur)?|instandsetzung|instandhaltung)\b/i,
  /\b(sachbearbeiter|kaufmann|kauffrau|verwaltung(?:sfachangestellte)?)\b/i,
  /\b(eventmanager|eventdekoration|veranstaltung|gastronomie|k(?:ü|ue)chenleiter)\b/i,
];

const jobTitle = (item.title || '').trim();
const TECH_SAFEGUARD = /developer|engineer|architect|entwickl|informatik|consultant|berater|programm|software|cloud|devops|salesforce|sap\b|data\s*engineer|platform/i;
const rawReject = ROLE_REJECT_PATTERNS.some(pattern => pattern.test(jobTitle))
  || (/\bvertrieb\b/i.test(jobTitle) && !TECH_SAFEGUARD.test(jobTitle));
// If the title ALSO contains a tech-role keyword, let Gemini decide instead of hard-rejecting.
// Unambiguous non-tech patterns (gastronomie, sachbearbeiter, etc.) rarely co-occur with tech terms,
// so the safeguard primarily rescues borderline titles like \"DevOps Engineer - Recruiting Platform\".
const rejected = rawReject && !TECH_SAFEGUARD.test(jobTitle);

if (rejected) {
  return {
    json: {
      ...item,
      _skip: true,
      _preFilterReject: true,
      _skipReason: `Role type "${jobTitle}" is fundamentally misaligned with developer profile (pre-filter reject)`,
      matchResult: {
        match: false,
        confidence: 0,
        reason: `Role type "${jobTitle}" is fundamentally misaligned with developer profile (pre-filter reject)`,
        jobType: 'unknown',
        _preFilterReject: true,
      },
    },
  };
}

// MUST include "JSON" for Gemini response_format
const systemPrompt = `You are a job-match filter for a Salesforce Developer / Software Developer seeking tech roles in Germany.

Return ONLY valid JSON. No explanation, no text outside JSON.

Output format:
{
  "match": true or false,
  "confidence": number (0-100),
  "reason": "one short line explaining WHY this confidence score",
  "jobType": "internship|werkstudent|full-time|contract|unknown"
}

CONFIDENCE CALIBRATION (use the full 0-100 range):
- 90-100: Core match — Salesforce Developer, Salesforce Consultant, or closely related CRM/platform role
- 75-89: Strong match — software development role where candidate skills are directly applicable (backend, full-stack, integration, DevOps)
- 60-74: Moderate match — tech-adjacent role where some skills transfer but significant gaps exist (e.g., pure frontend, QA/testing, data engineering)
- 40-59: Weak match — tech role but poor skill alignment (e.g., embedded systems, C++/low-level, pure ML research)
- 20-39: Very weak — role has some IT connection but is not a developer position (e.g., IT project management, tech sales, system admin)
- 0-19: No match — completely unrelated field

MATCH RULES:
- match=true if confidence >= 45
- match=false if confidence < 45

EXAMPLES (use these to calibrate your confidence scores):
- "Salesforce Developer" at SAP: {"match":true,"confidence":95,"reason":"Core Salesforce platform role","jobType":"full-time"}
- "Junior Backend Developer (Python/Node.js)" at Zalando: {"match":true,"confidence":78,"reason":"Software dev role with overlapping JS/Python stack","jobType":"full-time"}
- "IT Project Manager" at Siemens: {"match":false,"confidence":28,"reason":"Management role, not hands-on development","jobType":"full-time"}
- "Werkstudent Softwareentwicklung" at BMW: {"match":true,"confidence":68,"reason":"Entry-level tech role, transferable development skills","jobType":"werkstudent"}
- "Senior DevOps Engineer" at Delivery Hero: {"match":true,"confidence":72,"reason":"Infrastructure role, candidate has CI/CD and AWS experience","jobType":"full-time"}
- "Werkstudent Cloud / DevOps" at N26: {"match":true,"confidence":80,"reason":"Direct match for AWS/Terraform project experience, student-friendly hours","jobType":"werkstudent"}
- "Remote Full-Stack Engineer (EU)" at a Berlin startup: {"match":true,"confidence":75,"reason":"React + Node stack matches, fully remote","jobType":"full-time"}
- "Software Engineering Intern" at SAP: {"match":true,"confidence":72,"reason":"Tech internship, skill overlap, eligible via student visa","jobType":"internship"}
- "Part-time Salesforce Developer (20h/week)" at a consultancy: {"match":true,"confidence":90,"reason":"Core expertise, matches Werkstudent hour cap","jobType":"werkstudent"}
- "Sachbearbeiter Vertriebsinnendienst" at Bosch: {"match":false,"confidence":5,"reason":"Administrative sales support, no tech component","jobType":"full-time"}

IMPORTANT DISTINCTIONS:
- "Salesforce" in a role title means CRM platform development — this is the candidate PRIMARY expertise. High confidence.
- "Sales" in a role title (without "force") means selling products/services — this is NOT the candidate field. Low confidence.
- "Business Development Manager", "Account Executive", "Sales Manager" = sales roles, NOT tech roles. Confidence 0-20.
- "Projektleiter" / "Project Manager" without "IT" or "Software" qualifier = generic management. Confidence 10-30.
- "Sachbearbeiter" / "Clerk" = administrative role. Confidence 0.
- "Linienführer" / "Line Leader" = manufacturing/production. Confidence 0.
- "Inbetriebnahme" / "Commissioning" = industrial engineering. Confidence 0.
- Internship / Werkstudent / part-time in ANY tech field: confidence 60+ (be lenient — candidate is explicitly open to all these formats)
- Junior roles in software/IT: confidence 65+ (transferable skills)
- Remote tech roles based anywhere in DACH or EU: do NOT penalize for being remote — candidate is open to remote
- Roles with "Werkstudent", "Praktikum", "Intern", "Teilzeit", or "part-time" in the title: these are HIGH-priority matches for this candidate — bias confidence +10 if tech-aligned

CANDIDATE PROFILE (for your reference when judging match):
- Education: M.Sc. Global Software Development at Hochschule Fulda (Germany, ongoing) + B.E. Information Technology (CGPA 8.83/10 ≈ German 1.5).
- Visa status: Student visa — eligible for Werkstudent (20h/week during semester, 40h/week during breaks), internships, and full-time after graduation.
- Open to: internship, Werkstudent, part-time, full-time, and remote roles across DACH + EU — be LENIENT on role type when tech alignment is strong.
- Core Salesforce: Apex, LWC, Aura, Flows, Sales/Service/Experience/Data Cloud, Agentforce, Salesforce DX, AppExchange managed package shipped through full security review, 85%+ Apex test coverage. Certified Platform Developer I, Agentforce Specialist, Data Cloud Consultant.
- Software engineering: JavaScript, TypeScript, Python, C, Node.js, Express, React, Tailwind CSS, Phaser.js, REST/SOAP APIs, WebRTC, Socket.IO, Supabase (PostgreSQL), MySQL, MongoDB.
- Cloud & DevOps: AWS (VPC, EC2, ALB, ASG, RDS, EFS, WAF), Terraform (IaC, ~41 resources), Docker, Jenkins CI/CD, GitHub Actions, Git, HPC/SLURM, MPI.
- Automation & AI: n8n, Zapier, Agentforce Agent Builder, Prompt Templates, Playwright, AI-assisted engineering.
- Notable hands-on projects: real-time spatial communication platform (WebRTC + Socket.IO), production AWS/Terraform stack, AI document generation pipeline (n8n + OpenAI + Playwright), distributed SUMMA matrix-multiply in C+MPI, LWC-based Custom Form Builder.
- Languages: English C1, German active learner.
`;

// ===== Helper =====
const clean = (s) => (s || '').replace(/\s+/g, ' ').trim();

// ===== Resume Data =====
const skills = (item.resume?.currentSkills || [])
  .map(s => s?.skill || '')
  .filter(Boolean)
  .join(', ');

const education = (item.resume?.education || [])
  .map(e =>
    `${e.degree || ''} ${e.field || ''} at ${e.institution || ''} (${e.year || ''})`.trim()
  )
  .join('; ');

const recentWork = (item.resume?.currentWork || [])
  .slice(0, 2)
  .map(w =>
    `${w.jobTitle || ''} at ${w.employer || ''}: ${(w.description || '').slice(0, 120)}`
  )
  .join(' | ');

const projectsDigest = (item.resume?.currentProjects || [])
  .slice(0, 5)
  .map(p => `${p.name} (${p.techStack || 'n/a'})`)
  .join(' | ');

// ===== Smart JD Extraction (EN + DE aware) =====
const jdRaw = item.description || '';
const jd = clean(jdRaw);

// Split by important sections (English + German)
const parts = jd.split(
  /requirements|qualifications|your profile|anforderungen|qualifikationen|profil|was Sie mitbringen|was du mitbringst/i
);

// Pick best section or fallback
const hasRequirements = parts.length > 1 && parts[1].trim().length > 120;
let jdImportant = hasRequirements ? parts[1] : jd;

if (hasRequirements && jd.length > 400) {
  jdImportant = `${jd.slice(0, 300)}\n\n${jdImportant}`;
}

// Filter out benefits/offer sections that waste tokens
jdImportant = jdImportant.replace(/(?:^|\n)\s*(?:was wir bieten|what we offer|benefits|unsere leistungen|unser angebot|wir bieten dir|das bieten wir|your benefits|perks)\s*[\s\S]{0,800}/gi, '');

// Remove HTML tags if present
jdImportant = jdImportant.replace(/<[^>]+>/g, '');

// Final cap for token safety
jdImportant = jdImportant.slice(0, 1500);

// ===== Build User Prompt =====
const userMsg = `Candidate:
Title: ${item.resume?.currentJobTitle || 'Software Developer'}
Location: Germany

Education:
${education || 'MSc Global Software Development, Hochschule Fulda Germany'}

Recent Work:
${recentWork || 'N/A'}

Skills:
${skills || 'N/A'}

Key Projects:
${projectsDigest || 'N/A'}

Job:
${item.title} at ${item.company}
Location: ${item.location}
Seniority: ${item.seniority || 'unspecified'}

Job Description:
${jdImportant}`;

// ===== Final Output =====
return {
  json: {
    ...item,
    _geminibody: {
      contents: [
        {
          role: 'user',
          parts: [
            {
              text: `${systemPrompt}\n\n${userMsg}`
            }
          ]
        }
      ],
      generationConfig: {
        temperature: 0.3,
        responseMimeType: 'application/json'
      }
    },
  },
};

// 8. Parse Match Result

const aiResponse = $json;
const jobData = $('10a. Build Match Prompt').item.json;
const { _geminibody, ...cleanJobData } = jobData;

// Short-circuit: item was pre-filter rejected (no Gemini call made)
if (cleanJobData.matchResult && cleanJobData.matchResult._preFilterReject) {
  return {
    json: cleanJobData,
  };
}

// Handle rate limit or API error from 10c. Gemini API Call
if (aiResponse.error) {
  return {
    json: {
      ...cleanJobData,
      matchResult: {
        match: false,
        confidence: 0,
        reason: 'Gemini API error: ' + (aiResponse.error.message || 'unknown'),
        jobType: 'unknown',
        _apiError: true,
      },
    },
  };
}

try {
  const content = aiResponse.candidates[0].content.parts[0].text;
  const result = JSON.parse(content);
  return {
    json: {
      ...cleanJobData,
      matchResult: { ...result, _apiError: false },
    },
  };
} catch (err) {
  return {
    json: {
      ...cleanJobData,
      matchResult: {
        match: false,
        confidence: 0,
        reason: 'AI parse error – skipped: ' + err.message,
        jobType: 'unknown',
        _apiError: true,
      },
    },
  };
}

// Single combined AI call returns both patch and coverLetter

// Current item = OpenAI HTTP response for this job
const aiResponse = $json;

// Original job from 13a, matched by index
const jobData = $('13a. Build Tailor Prompt').item.json;

let patch = {};
let coverLetter = '';
let language = 'de';

try {
  if (!aiResponse?.choices?.[0]?.message?.content) {
    throw new Error('No choices in AI response — possible rate limit or API error');
  }
  const result = JSON.parse(aiResponse.choices[0].message.content);
  patch = result.patch || {};
  coverLetter = result.coverLetter || '';
  language = result.language === 'en' ? 'en' : 'de';

  // ===== Structural Validation =====
  // Reject patches that will produce weak resumes — catch before wasting PDF generation
  const validationErrors = [];

  // Must have work AND skills — profile-only patches produce generic resumes
  const hasWork = Array.isArray(patch.work) && patch.work.length > 0;
  const hasSkills = Array.isArray(patch.skills) && patch.skills.length > 0;
  if (!hasWork) validationErrors.push('patch.work is missing or empty');
  if (!hasSkills) validationErrors.push('patch.skills is missing or empty');

  // Work entries must have id and non-empty description
  if (hasWork) {
    for (const w of patch.work) {
      if (!w || typeof w !== 'object') {
        validationErrors.push('work contains non-object entry');
        continue;
      }
      if (!w.id) validationErrors.push('work entry missing id');
      if (!w.description || w.description.trim().length < 20) {
        validationErrors.push('work entry ' + (w.id || '?') + ' has empty/trivial description');
      }
    }
  }

  // Skill entries must have id and non-empty infoHtml
  if (hasSkills) {
    for (const s of patch.skills) {
      if (!s || typeof s !== 'object') {
        validationErrors.push('skills contains non-object entry');
        continue;
      }
      if (!s.id) validationErrors.push('skill entry missing id');
      if (!s.infoHtml || s.infoHtml.trim().length < 5) {
        validationErrors.push('skill entry ' + (s.id || '?') + ' has empty/trivial infoHtml');
      }
    }
  }

  if (validationErrors.length > 0) {
    patch._error = 'Structural validation failed: ' + validationErrors.join('; ');
  }
} catch (err) {
  patch = { _error: 'AI parse failed: ' + err.message };
  coverLetter = '';
}

let paragraph1 = '';
let paragraph2 = '';
let paragraph3 = '';
let _coverLetterWarning = '';

if (typeof coverLetter === 'object' && coverLetter !== null) {
  // New structured format: { paragraph1, paragraph2, paragraph3 }
  paragraph1 = (coverLetter.paragraph1 || '').trim();
  paragraph2 = (coverLetter.paragraph2 || '').trim();
  paragraph3 = (coverLetter.paragraph3 || '').trim();

  if (!paragraph1 || !paragraph2 || !paragraph3) {
    _coverLetterWarning = 'Cover letter object missing one or more paragraph fields';
  }
} else if (typeof coverLetter === 'string' && coverLetter.length > 0) {
  // Legacy fallback: single string with \n\n separators
  const rawParts = coverLetter
    .split(/\n\n+/)
    .map(p => p.trim())
    .filter(p => p.length > 0);

  paragraph1 = rawParts[0] || '';
  paragraph2 = rawParts[1] || '';
  paragraph3 = rawParts[2] || '';

  if (rawParts.length < 3) {
    _coverLetterWarning = `Cover letter has ${rawParts.length} paragraph(s), expected 3`;
    // Sentence-split recovery for legacy single-block responses
    if (rawParts.length === 1 && rawParts[0].length > 100) {
      const sentences = rawParts[0].split(/(?<=[.!?])\s+(?=[A-Z\u00C4\u00D6\u00DC])/);
      if (sentences.length >= 3) {
        const third = Math.floor(sentences.length / 3);
        const p1 = sentences.slice(0, third).join(' ');
        const p2 = sentences.slice(third, third * 2).join(' ');
        const p3 = sentences.slice(third * 2).join(' ');
        if (p1.length >= 40 && p2.length >= 40 && p3.length >= 40) {
          paragraph1 = p1;
          paragraph2 = p2;
          paragraph3 = p3;
          _coverLetterWarning += ' — recovered via sentence split (legacy format)';
        }
      }
    }
  }
} else {
  _coverLetterWarning = 'AI returned empty cover letter';
}


// ===== Quality Flag =====
// Detect signs of weak fit based on patch content
let _qualityFlag = 'Good Fit';

if (patch._error) {
  _qualityFlag = 'Error';
} else {
  // Check if skill categories were renamed to non-tech domains
  const NON_TECH_DOMAINS = /\bsales\b|\bmarketing\b|\blogistics\b|\bhr\b|\bhuman\s*resource\b|\bcustomer\s*service\b|\baccounting\b|\bfinance\b|\bbusiness\s*development\b/i;
  const SALESFORCE_PATTERN = /salesforce/i;
  const renamedSkills = (patch.skills || [])
    .filter(s => s.skill)
    .map(s => s.skill);
  const hasFabricatedSkills = renamedSkills.some(name =>
    NON_TECH_DOMAINS.test(name) && !SALESFORCE_PATTERN.test(name)
  );

  if (hasFabricatedSkills) {
    _qualityFlag = 'Bad Fit';
  } else if (_coverLetterWarning && _coverLetterWarning.includes('sentence split')) {
    _qualityFlag = 'Review';
  }

  // Check if AI actually tailored work and skills (not just title/profile)
  const hasWorkChanges = Array.isArray(patch.work) && patch.work.length > 0;
  const hasSkillChanges = Array.isArray(patch.skills) && patch.skills.length > 0;
  if (_qualityFlag === 'Good Fit' && (!hasWorkChanges || !hasSkillChanges)) {
    _qualityFlag = 'Review';
  }
}

return {
  json: {
    patch,
    coverLetter,
    language,
    paragraph1,
    paragraph2,
    paragraph3,
    _coverLetterWarning,
    _qualityFlag,
    job: {
      source:          jobData.source || '',
      title:           jobData.title || '',
      company:         jobData.company || '',
      location:        jobData.location || '',
      url:             jobData.url || '',
      applyUrl:        jobData.applyUrl || '',
      postedAt:        jobData.postedAt || '',
      salary:          jobData.salary || '',
      jobType:         jobData.matchResult?.jobType || 'unknown',
      matchConfidence: jobData.matchResult?.confidence || 0,
      matchReason:     jobData.matchResult?.reason || '',
    },
  },
};

const patchItems = $('14. Parse AI Patch').all();
const inputs = $input.all();

// Capture error details from failed PDF calls
const errorItems = inputs.filter(i => i.json.error || (i.json.statusCode && i.json.statusCode >= 400));
const pdfErrorMsg = errorItems.map(e => e.json.error?.message || e.json.message || JSON.stringify(e.json.error || '')).filter(Boolean).join('; ');

// Build lookup maps by jobId — immune to index shifts from failed PDF calls
const resumeByJobId = new Map();
const coverByJobId = new Map();
for (const item of inputs) {
  const fn = item.json.fileName || '';
  const jid = item.json.jobId || '';
  if (!jid) continue;
  if (fn.startsWith('resume')) resumeByJobId.set(jid, item);
  else if (fn.startsWith('coverletter')) coverByJobId.set(jid, item);
}

const now = new Date();
const dateStr = now.toISOString().slice(0, 10);

return patchItems.map((item) => {
  const patchData = item.json;
  const jobUrl = patchData.job?.url || '';
  const resumeItem = resumeByJobId.get(jobUrl) || { json: {} };
  const coverItem = coverByJobId.get(jobUrl) || { json: {} };

  return {
    json: {
      Date:                dateStr,
      Company:             patchData.job?.company          || '',
      Role:                patchData.job?.title            || '',
      'Job Type':          patchData.job?.jobType          || '',
      Location:            patchData.job?.location         || '',
      Source:              patchData.job?.source           || '',
      'Job URL':           patchData.job?.url ? '=HYPERLINK("' + patchData.job.url.replace(/"/g, '""') + '","View Job")' : '',
      'Apply URL':         patchData.job?.applyUrl ? '=HYPERLINK("' + patchData.job.applyUrl.replace(/"/g, '""') + '","Apply")' : '',
      'Raw URL':           patchData.job?.url || '',
      'Match Confidence':  patchData.job?.matchConfidence  || 0,
      'Match Reason':      patchData.job?.matchReason      || '',
      'Resume File':       resumeItem.json.file            || '',
      'Cover Letter File': coverItem.json.file             || '',
      Status:              (resumeItem.json.success && coverItem.json.success) ? 'Generated' : 'PDF Failed',
      Applied:             'No',
      Response:            '',
      Interview:           '',
      Notes:               patchData.patch?._error || pdfErrorMsg || patchData._coverLetterWarning || '',
      Quality:             patchData._qualityFlag  || 'Unknown',
    },
  };
});

const jobData = $json;
const now = new Date();

// Sentinel: no new jobs today
if (jobData.skipped) {
  return {
    json: {
      Date:               now.toISOString().slice(0, 10),
      Company:            '',
      Role:               '',
      'Job Type':         '',
      Location:           '',
      Source:             '',
      'Job URL':          '',
      'Apply URL':        '',
      'Match Confidence': 0,
      'Match Reason':     '',
      'Resume File':      '',
      'Cover Letter File': '',
      Status:             'No New Jobs',
      Applied:            'N/A',
      Response:           '',
      Interview:          '',
      Notes:              jobData.message || '',
      Quality:            'N/A',
    }
  };
}

const isPreFilter = !!jobData._preFilterReject;
const isApiError = !!jobData.matchResult?._apiError;
const isSentinel = !!jobData._pipelineSentinel;

if (isSentinel) {
  return {
    json: {
      Date:               now.toISOString().slice(0, 10),
      Company:            '',
      Role:               '',
      'Job Type':         '',
      Location:           '',
      Source:             '',
      'Job URL':          '',
      'Apply URL':        '',
      'Match Confidence': 0,
      'Match Reason':     '',
      'Resume File':      '',
      'Cover Letter File': '',
      Status:             jobData.error ? 'Pipeline Error' : 'No New Jobs',
      Applied:            'N/A',
      Response:           '',
      Interview:          '',
      Notes:              jobData.message || '',
      Quality:            'N/A',
    }
  };
}

return {
  json: {
    Date:               now.toISOString().slice(0, 10),
    Company:            jobData.company || '',
    Role:               jobData.title || '',
    'Job Type':         jobData.matchResult?.jobType || '',
    Location:           jobData.location || '',
    Source:             jobData.source || '',
    'Job URL':          jobData.url ? '=HYPERLINK("' + jobData.url.replace(/"/g, '""') + '","View Job")' : '',
    'Apply URL':        jobData.applyUrl ? '=HYPERLINK("' + jobData.applyUrl.replace(/"/g, '""') + '","Apply")' : '',
    'Raw URL':          jobData.url || '',
    'Match Confidence': jobData.matchResult?.confidence || 0,
    'Match Reason':     jobData.matchResult?.reason || (isPreFilter ? 'Pre-filter reject' : ''),
    'Resume File':      '',
    'Cover Letter File': '',
    Status:             isApiError ? 'Manual Review - API Error' : isPreFilter ? 'Skipped - Pre-Filter Reject' : 'Skipped - No Match',
    Applied:            isApiError ? '' : 'N/A',
    Response:           '',
    Interview:          '',
    Notes:              jobData._skipReason || jobData.matchResult?.reason || '',
    Quality:            isApiError ? 'Manual Review' : isPreFilter ? 'Pre-Filter Reject' : 'Skipped',
  }
};

